void *bridge_void_ptr(void *target_ptr)
{
    if (!target_ptr) {
        return nullptr;
    }
    auto target = reinterpret_cast<void_ptr_sysv_t>(target_ptr);
    std::lock_guard<std::mutex> lock(void_ptr_mutex);
    for (size_t i = 0; i < 16384; ++i) {
        if (reinterpret_cast<void_ptr_sysv_t>(void_ptr_targets[i].load(std::memory_order_acquire)) == target) {
            void_ptr_refcounts[i].fetch_add(1, std::memory_order_relaxed);
            return reinterpret_cast<void *>(void_ptr_thunks[i]);
        }
    }
    for (size_t i = 0; i < 16384; ++i) {
        if (void_ptr_targets[i].load(std::memory_order_acquire) == 0) {
            void_ptr_targets[i].store(reinterpret_cast<uintptr_t>(target), std::memory_order_release);
            void_ptr_refcounts[i].store(1, std::memory_order_relaxed);
            return reinterpret_cast<void *>(void_ptr_thunks[i]);
        }
    }
    fprintf(stderr,
            "FATAL: Havok callback bridge pool exhausted for the 'void_ptr' signature family:\n"
            "  All 16384 bridge slots are in use. Every live Havok callback with this\n"
            "  signature consumes one slot, so worlds with very many grids/blocks (e.g. thousands\n"
            "  of thrusters or listeners) can register more callbacks than the pool can hold.\n"
            "  Fix: raise CALLBACK_SLOTS (currently 16384) in tools/generate_havok_thunks.py,\n"
            "  regenerate the thunks (python3 tools/generate_havok_thunks.py), and rebuild.\n");
    std::abort();
}

void release_void_ptr(void *target_ptr)
{
    if (!target_ptr) {
        return;
    }
    auto target = reinterpret_cast<void_ptr_sysv_t>(target_ptr);
    std::lock_guard<std::mutex> lock(void_ptr_mutex);
    for (size_t i = 0; i < 16384; ++i) {
        if (reinterpret_cast<void_ptr_sysv_t>(void_ptr_targets[i].load(std::memory_order_acquire)) == target) {
            auto refs = void_ptr_refcounts[i].load(std::memory_order_relaxed);
            if (refs > 0) {
                refs = void_ptr_refcounts[i].fetch_sub(1, std::memory_order_acq_rel) - 1;
            }
            if (refs == 0) {
                void_ptr_targets[i].store(0, std::memory_order_release);
            }
            return;
        }
    }
}
